## Injection Points

### I/O operation results

```rust
impl Reactor for LabReactor {
    fn poll(&self, events: &mut Events, timeout: Option<Duration>) -> io::Result<usize> {
        // Normal poll logic...

        // Chaos injection: fail some I/O ops
        if let Some(chaos) = &mut self.chaos {
            for event in events.iter_mut() {
                if chaos.should_inject(chaos.config.io_error_probability) {
                    // Replace with error event
                    event.mark_error(chaos.random_io_error());

                    tracing::debug!(
                        target: "chaos",
                        token = %event.token,
                        injection = "io_error",
                        error_kind = ?chaos.last_error_kind(),
                    );
                }
            }
        }

        Ok(count)
    }
}
```

